mapper.select:

	SELECT SSVC_LINE_TYPE_CD, SASSIGN_TYPE_CD, SIP_VERSION_TYPE_CD, SIP_CREATE_TYPE_CD,
			NIP_ASSIGN_MST_SEQ, SIP_BLOCK, NBITMASK,SFIRST_ADDR,
			SLAST_ADDR, DMODIFY_DT, ROWNUM AS PRIORITY
	 FROM MST.tb_ip_assign_mst
	 WHERE sassign_level_cd =  'IA0004'

	 	AND sip_block like #{sipAddressSearchKey,jdbcType=VARCHAR}||'%'

	 AND ssvc_line_type_cd = #{ssvcLineTypeCd, jdbcType=CHAR}
	 AND sassign_type_cd = #{assignTypeCd, jdbcType=CHAR} 
	 AND sip_version_type_cd = #{ipVersionTypeCd, jdbcType=CHAR}
	 AND sip_create_type_cd =  #{ipCreateTypeCd, jdbcType=CHAR} 

	 	AND nbitmask = #{ipbitmask, jdbcType=INTEGER} -- MAX 64

	 AND nlvl_mst_seq IN (SELECT DISTINCT nlvl_mst_seq FROM MST.TB_lvl_mst WHERE ssvc_line_type_cd = #{ssvcLineTypeCd, jdbcType=CHAR}
				AND ssvc_obj_cd IN ( SELECT slvl_cd FROM MST.TB_Lvl_SUB_CD 
							WHERE sLOFFICECODE = #{icisofficescode,jdbcType=VARCHAR}
							AND ssvc_line_type_cd = #{ssvcLineTypeCd, jdbcType=CHAR} ))			
	ORDER BY NPRIORITY , PIP_PREFIX
 	LIMIT 300

SELECT A.SIP_BLOCK , A.NBITMASK , A.DMODIFY_DT , DETAIL_RSLT FROM ( SELECT A.SIP_BLOCK , A.NBITMASK , (CASE WHEN A.DMODIFY_DT = A.DCREATE_DT THEN NULL WHEN A.DMODIFY_DT != A.DCREATE_DT THEN A.DMODIFY_DT ELSE NULL END) AS DMODIFY_DT , mst.fn_summary_suggest_ip_list_sdn(A.nip_assign_mst_seq) AS DETAIL_RSLT FROM MST.tb_ip_assign_mst A INNER JOIN MST.TB_IPMS_SVC_MST B ON B.NIPMS_SVC_SEQ = A.NIPMS_SVC_SEQ WHERE A.sassign_level_cd = 'IA0004'
AND A.sip_block like #{sipAddressSearchKey,jdbcType=VARCHAR}||'%'
AND A.ssvc_line_type_cd = #{ssvcLineTypeCd, jdbcType=CHAR} AND A.sassign_type_cd = #{assignTypeCd, jdbcType=CHAR} AND A.sip_version_type_cd = #{ipVersionTypeCd, jdbcType=CHAR} AND A.sip_create_type_cd = #{ipCreateTypeCd, jdbcType=CHAR}
AND A.nbitmask = #{ipbitmask, jdbcType=INTEGER} -- MAX 64
AND A.nlvl_mst_seq IN (SELECT DISTINCT nlvl_mst_seq FROM MST.TB_lvl_mst WHERE ssvc_line_type_cd = #{ssvcLineTypeCd, jdbcType=CHAR} AND ssvc_obj_cd IN ( SELECT slvl_cd FROM MST.TB_Lvl_SUB_CD WHERE sLOFFICECODE = #{icisofficescode,jdbcType=VARCHAR} AND ssvc_line_type_cd = #{ssvcLineTypeCd, jdbcType=CHAR} )) ORDER BY A.NPRIORITY , A.PIP_PREFIX
LIMIT #{nlimit,jdbcType=INTEGER}
) A

SELECT 
		TO_CHAR(COUNT(*)) AS CNT
	 FROM MST.tb_ip_assign_mst A
	 	INNER JOIN MST.TB_IPMS_SVC_MST B
	 		ON B.NIPMS_SVC_SEQ = A.NIPMS_SVC_SEQ
	 WHERE A.sassign_level_cd =  'IA0004'


	 		AND A.sip_block like #{sipAddressSearchKey,jdbcType=VARCHAR}||'%'


	 AND A.ssvc_line_type_cd = #{ssvcLineTypeCd, jdbcType=CHAR}
	 AND A.sassign_type_cd = #{assignTypeCd, jdbcType=CHAR} 
	 AND A.sip_version_type_cd = #{ipVersionTypeCd, jdbcType=CHAR}
	 AND A.sip_create_type_cd =  #{ipCreateTypeCd, jdbcType=CHAR}

	 	AND A.nbitmask = #{ipbitmask, jdbcType=INTEGER} -- MAX 64

	 AND A.nlvl_mst_seq IN (SELECT DISTINCT nlvl_mst_seq FROM MST.TB_lvl_mst WHERE ssvc_line_type_cd = #{ssvcLineTypeCd, jdbcType=CHAR}
				AND ssvc_obj_cd IN ( SELECT slvl_cd FROM MST.TB_Lvl_SUB_CD 
							WHERE sLOFFICECODE = #{icisofficescode,jdbcType=VARCHAR}
							AND ssvc_line_type_cd = #{ssvcLineTypeCd, jdbcType=CHAR} ))

   SELECT 
		A.NIP_ASSIGN_MST_SEQ
	FROM MST.TB_IP_ASSIGN_MST A
	WHERE
		A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=VARCHAR}
		AND A.SIP_BLOCK = #{sipBlock, jdbcType=VARCHAR}
		AND A.NBITMASK = #{nbitmask, jdbcType=INTEGER}

  SELECT COUNT(*) FROM MST.TB_IP_ALLOC_MST A
	WHERE
		A.SIP_BLOCK = #{ipBlock,jdbcType=VARCHAR}
		AND A.NBITMASK = #{ipbitmask,jdbcType=VARCHAR}
		AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd,jdbcType=VARCHAR}

SELECT NRESULT FROM(
	SELECT BIF.UF_WS_INSERTFIXIPLIST_SDN(
		#{regyn,jdbcType=VARCHAR}
		, #{said,jdbcType=VARCHAR}
		, #{nip_assign_mst_seq,jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.BigIntTypeHandler}
		, #{ssvc_line_type_cd,jdbcType=VARCHAR}
		, #{ip_block,jdbcType=VARCHAR}
		, #{ipbitmask,jdbcType=INTEGER}
		, #{gatewayIp,jdbcType=VARCHAR}
	) AS NRESULT)

SELECT 
	A.SSAID, A.SICISOFFICESCODE
FROM MST.TB_IP_ALLOC_MST  A
WHERE
	A.SIP_BLOCK = #{sipBlock,jdbcType=VARCHAR}
	AND A.NBITMASK = #{nbitmask,jdbcType=INTEGER}

SELECT 
	A.SSAID
	, A.SSVC_LINE_TYPE_CD
	, A.NIP_ASSIGN_MST_SEQ
	, A.SIP_BLOCK
	, A.NBITMASK
FROM MST.TB_IP_ALLOC_MST A
WHERE
	A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=VARCHAR} 
 	AND A.SIP_BLOCK = #{ipBlock, jdbcType=VARCHAR}
 	AND A.NBITMASK = #{ipbitmask, jdbcType=INTEGER}
 	AND A.SSAID = #{said,jdbcType=VARCHAR}

SELECT NRESULT FROM(
	SELECT BIF.UF_WS_INSERTRESERVEDIPLIST_SDN(
		#{sordernum,jdbcType=VARCHAR}
		, #{regyn,jdbcType=VARCHAR}
		, #{said,jdbcType=VARCHAR}
		, #{nip_assign_mst_seq,jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.BigIntTypeHandler}
		, #{ssvc_line_type_cd,jdbcType=VARCHAR}
		, #{ip_block,jdbcType=VARCHAR}
		, #{ipbitmask,jdbcType=INTEGER}
		, #{gatewayIp,jdbcType=VARCHAR}
	) AS NRESULT)

mapper.insert:
INSERT INTO mst.tb_neoss_error_manage(
 ipbitmask
, nip_assign_mst_seq
, slacpblockyn 
, ip_block
, svc_use_type_cd
, ipms_svc_seq
, assign_type_cd
, ex_svc_cd
, ip_version_type_cd
, ip_create_type_cd
, sipaddr
, eipaddr
, gatewayip
, ssaid
, sllnum
, error_result_cd)
VALUES
(
	#{ipbitmask, jdbcType=INTEGER}
	, #{nipAssignMstSeq, jdbcType=BIGINT}
	, #{slacpBlockYN,jdbcType=VARCHAR}
	, #{ipBlock,jdbcType=VARCHAR}
	, #{svcUseTypeCd,jdbcType=VARCHAR}
	, #{ipmsSvcSeq, jdbcType=BIGINT}
	, #{assignTypeCd, jdbcType=CHAR}
	, #{exSvcCd, jdbcType=VARCHAR}
	, #{ipVersionTypeCd, jdbcType=CHAR}
	, #{ipCreateTypeCd, jdbcType=CHAR}
	, #{sipaddr, jdbcType=VARCHAR}
	, #{eipaddr, jdbcType=VARCHAR}
	, #{gatewayip, jdbcType=VARCHAR}
	, #{said, jdbcType=VARCHAR}
	, #{llnum, jdbcType=VARCHAR}
	, 'NE0001'
)
